def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 2:
            priorities[i] = ratio ** 5 + np.exp(ratio / 2)
            for m in range(1, 4):
                priorities[i] += np.sin(ratio * m) / (m + 1)
        elif 1 < ratio <= 2:
            priorities[i] = ratio ** 3 + np.log1p(ratio) * 2
            if bin_capacity < item * 2:
                priorities[i] *= 1.5
            else:
                for n in range(2, 5):
                    priorities[i] += (bin_capacity / (item * n)) ** 0.3 / (n)
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 8):
                term = (ratio ** j) / (j ** 1.5)
                if j % 3 == 0:
                    term *= 1.1
                elif j % 2 == 0:
                    term *= 0.9
                else:
                    term *= 1.05
                score += term
            if bin_capacity < item * 1.2:
                score *= 2.5
                for p in range(1, 3):
                    score += np.log1p(bin_capacity / (item * p)) / (p + 1)
            elif bin_capacity < item * 2.5:
                score *= 1.4
                for q in range(1, 4):
                    score += (bin_capacity / (item * q)) ** 0.6 / (q + 2)
            else:
                for k in range(1, 5):
                    score += (bin_capacity / (item * k)) ** 0.4 / (k + 1)
                if bin_capacity > item * 5:
                    score -= np.sqrt(bin_capacity - item * 5) / 10
            priorities[i] = max(score, 0)
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        min_priority = np.min(finite_priorities)
    else:
        max_priority = 1
        min_priority = 0
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 4
        elif priorities[i] < 0:
            priorities[i] = min_priority
        elif priorities[i] > max_priority:
            priorities[i] = max_priority
    return priorities
